package br.edu.cafeteria.modelo; import br.edu.cafeteria.excecao.PontosInsuficientesException; public class ClienteVIP extends Cliente{public ClienteVIP(String n,String c){super(n,c);}public int calcularXP(double v){return (int)(v*2);}public void pagarComXP(double valor)throws PontosInsuficientesException{int nec=(int)(valor*XP_POR_REAL);if(getXp()<nec)throw new PontosInsuficientesException("XP insuficiente");removerXP(nec);}}
